{"path": "/tmp/sv-5293a463f5fe41ad971cc3dd816aa947/Components/Pages/Catalog/CatalogPagination.razor", "file_text": "<nav style="display:flex;justify-content:center;align-items:center;gap:4px;margin-top:24px;flex-wrap:wrap;" aria-label="Product catalog pagination">
    <button disabled="@(Page <= 1)" @onclick="() => GoToPage(Page - 1)"
            style="padding:6px 12px;border:1px solid #ccc;border-radius:4px;background:#fff;cursor:pointer;">
        Previous
    </button>

    @for (int i = 1; i <= TotalPages; i++)
    {
        var pageNum = i;
        <button @onclick="() => GoToPage(pageNum)"
                style="padding:6px 12px;border:1px solid @(pageNum == Page ? "#0d6efd" : "#ccc");border-radius:4px;background:@(pageNum == Page ? "#0d6efd" : "#fff");color:@(pageNum == Page ? "#fff" : "#333");cursor:pointer;">
            @pageNum
        </button>
    }

    <button disabled="@(Page >= TotalPages)" @onclick="() => GoToPage(Page + 1)"
            style="padding:6px 12px;border:1px solid #ccc;border-radius:4px;background:#fff;cursor:pointer;">
        Next
    </button>
</nav>

@code {
    [Parameter] public int Page { get; set; }
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int PageSize { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => PageSize > 0 ? (int)Math.Ceiling((double)TotalCount / PageSize) : 1;

    private async Task GoToPage(int page) => await OnPageChanged.InvokeAsync(page);
}
"}

