+        <span style="color:#f5a623;" aria-label="@($"Rating: {Product.Rating} out of 5")">@GetStarRating(Product.Rating)</span>
+        @if (!Product.InStock)
+        {
+            <span style="background:#dc3545;color:#fff;padding:2px 8px;border-radius:4px;font-size:0.75rem;align-self:flex-start;">Out of Stock</span>
+        }
+        <button @onclick="HandleAddToCart" @onclick:stopPropagation="true"
+                disabled="@(!Product.InStock)"
+                style="margin-top:auto;padding:8px 12px;border:none;border-radius:4px;cursor:pointer;background:@(Product.InStock ? "#0d6efd" : "#ccc");color:#fff;">
+            Add to Cart
+        </button>
+    </div>
+</div>
+
+@code {
+    [Parameter, EditorRequired] public Product Product { get; set; } = default!;
+    [Parameter] public EventCallback<Product> OnProductSelected { get; set; }
+    [Parameter] public EventCallback<Product> OnAddToCart { get; set; }
+
+    private async Task HandleCardClick() => await OnProductSelected.InvokeAsync(Product);
+    private async Task HandleAddToCart() => await OnAddToCart.InvokeAsync(Product);
+
+    private static string GetStarRating(double rating)
+    {
+        int full = (int)Math.Round(rating);
+        return new string('★', full) + new string('☆', 5 - full);
+    }
+}
+

