@using sv_5293a463f5fe41ad971cc3dd816aa947.Services

<div style="padding:16px;border:1px solid #ddd;border-radius:8px;">
    <h3 style="margin-top:0;">Filters</h3>

    <fieldset style="border:none;padding:0;margin:0 0 16px;">
        <legend style="font-weight:600;margin-bottom:8px;">Categories</legend>
        @foreach (var category in Categories)
        {
            <label style="display:block;margin-bottom:4px;cursor:pointer;">
                <input type="checkbox" checked="@_selectedCategories.Contains(category)"
                       @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                @category
            </label>
        }
    </fieldset>

    <div style="margin-bottom:16px;">
        <label style="font-weight:600;display:block;margin-bottom:4px;">Min Price</label>
        <input type="number" min="0" step="0.01" @bind="_minPrice"
               style="width:100%;padding:6px;border:1px solid #ccc;border-radius:4px;box-sizing:border-box;" />
    </div>

    <div style="margin-bottom:16px;">
        <label style="font-weight:600;display:block;margin-bottom:4px;">Max Price</label>
        <input type="number" min="0" step="0.01" @bind="_maxPrice"
               style="width:100%;padding:6px;border:1px solid #ccc;border-radius:4px;box-sizing:border-box;" />
    </div>

    <label style="display:block;margin-bottom:16px;cursor:pointer;">
        <input type="checkbox" @bind="_inStockOnly" />
        In Stock Only
    </label>

    <div style="display:flex;flex-direction:column;gap:8px;">
        <button @onclick="ApplyFilters"
                style="padding:8px 12px;background:#0d6efd;color:#fff;border:none;border-radius:4px;cursor:pointer;">
            Apply Filters
        </button>
        <button @onclick="ClearFilters"
                style="padding:8px 12px;background:#6c757d;color:#fff;border:none;border-radius:4px;cursor:pointer;">
            Clear Filters
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<string> Categories { get; set; } = [];
    [Parameter] public EventCallback<ProductFilter> OnApplyFilters { get; set; }

    private HashSet<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked) _selectedCategories.Add(category);
        else _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly);
        await OnApplyFilters.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnApplyFilters.InvokeAsync(new ProductFilter(null, null, null, false));
    }
}

@page "/catalog"
@using sv_5293a463f5fe41ad971cc3dd816aa947.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_error is not null)
{
    <div style="padding:16px;background:#f8d7da;color:#842029;border-radius:8px;margin-bottom:16px;">
        <strong>Error:</strong> @_error
        <button @onclick="LoadProducts" style="margin-left:12px;padding:4px 12px;border:1px solid #842029;border-radius:4px;background:transparent;color:#842029;cursor:pointer;">
            Retry
        </button>
    </div>
}

<div style="display:flex;gap:24px;align-items:flex-start;">
    <!-- Sidebar (25%) -->
    <div style="flex:0 0 25%;min-width:220px;">
        <CatalogSidebar Categories="_categories" OnApplyFilters="HandleApplyFilters" />
    </div>

    <!-- Main content (75%) -->
    <div style="flex:1;min-width:0;">
        <CatalogToolbar SortBy="@_sortBy"
                        TotalCount="_totalCount"
                        Page="_page"
                        PageSize="PageSize"
                        OnSortChanged="HandleSortChanged" />

        @if (_loading)
        {
            <div style="text-align:center;padding:48px;color:#888;">Loading products…</div>
        }
        else if (_products.Count == 0)
        {
            <div style="text-align:center;padding:48px;color:#888;">
                <p style="font-size:1.2rem;">No products found</p>
                <p>Try adjusting your filters.</p>
            </div>
        }
        else
        {
            <ProductGrid Products="_products"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />
        }

        @if (_totalCount > 0)
        {
            <CatalogPagination Page="_page"
                               TotalCount="_totalCount"
                               PageSize="PageSize"
                               OnPageChanged="HandlePageChanged" />
        }
    </div>
</div>

@code {
    private const int PageSize = 12;

    private List<Product> _products = [];
    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _page = 1;
    private int _totalCount;
    private bool _loading = true;
    private string? _error;

    /// <summary>Raised when a product card is clicked so the parent layout can navigate to detail.</summary>
    [Parameter] public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);
            await Task.WhenAll(categoriesTask, productsTask);

            _categories = categoriesTask.Result;
            ApplyResult(productsTask.Result);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task LoadProducts()
    {
        _loading = true;
        _error = null;
        try
        {
            var result = await ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);
            ApplyResult(result);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplyResult(PagedResult<Product> result)
    {
        _products = result.Items;
        _totalCount = result.TotalCount;
        _page = result.Page;
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        _filter = filter;
        _page = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _page = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        _page = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
        => await OnProductSelected.InvokeAsync(product);

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — wire up cart service when available
        return Task.CompletedTask;
    }
}

